#include<bits/stdc++.h>
using namespace std;
bool flag;
int a[1000005],l[1000005],r[1000005],n,ans=-1;
int dfs(int x,int y,int num)
{
    if(x==-1&&y==-1) return 0;
    if(x==-1||y==-1) flag=false;
    if(a[x]!=a[y]) flag=false;
    if(!flag) return 0;
    return dfs(l[x],r[y],2)+dfs(r[x],l[y],2)+num;
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i];
    for(int i=1;i<=n;i++) cin>>l[i]>>r[i];
    for(int i=1;i<=n;i++)
    {
        flag=true;
        int t=dfs(l[i],r[i],3);
        if(flag) ans=max(ans,t);
    }
    cout<<ans;
    return 0;
}
